mapper:
SELECT * FROM TF_CALENDAR_EVENT WHERE USER_ID = #{userId}
SELECT * FROM TF_CALENDAR_EVENT WHERE e_id = #{eId}
SELECT * FROM TF_CALENDAR_EVENT WHERE task_id = #{taskId}
SELECT * FROM TF_CALENDAR_EVENT WHERE EID = #{eId}
DELETE FROM TF_CALENDAR_EVENT WHERE E_ID = #{eId}
UPDATE TF_CALENDAR_EVENT SET NAME = #{name}, START_DATE = #{startDate}, END_DATE = #{endDate}, TYPE = #{type}, UPDATED_AT = SYSDATE WHERE ID = #{id}
SELECT * FROM TF_CALENDAR_EVENT WHERE USER_ID = #{userId} AND START_DATE BETWEEN TRUNC(SYSDATE, 'IW') AND TRUNC(SYSDATE, 'IW') + 7
WHEN MATCHED THEN UPDATE SET t.name = #{name}, t.start_date = #{startDate}, t.end_date = #{endDate}, t.e_tag = #{eTag}, t.updated_at = SYSDATE WHERE (t.e_tag IS NULL OR t.e_tag != #{eTag}) WHEN NOT MATCHED THEN INSERT ( ID, USER_ID, PROJECT_ID, TASK_ID, NAME, START_DATE, END_DATE, TYPE, CREATED_AT, UPDATED_AT, E_ID, E_TAG ) VALUES( SEQ_TF_CALENDAR_EVENT_PK.nextval, #{userId}, #{projectId}, #{taskId}, #{name}, #{startDate}, #{endDate}, #{type}, SYSDATE, SYSDATE, #{eId}, #{eTag} )
DELETE FROM TF_CALENDAR_EVENT WHERE E_ID NOT IN
#{eId}
